import{_ as s,o as e,c as t,a2 as n}from"./chunks/framework.LN3EJxkW.js";const b=JSON.parse('{"title":"客户端、服务器、浏览器与搜索引擎","description":"","frontmatter":{},"headers":[],"relativePath":"01-frontend/notes/00-web-basics/07-clients-servers-browsers-search-engines.md","filePath":"01-frontend/notes/00-web-basics/07-clients-servers-browsers-search-engines.md","lastUpdated":null}'),i={name:"01-frontend/notes/00-web-basics/07-clients-servers-browsers-search-engines.md"};function r(l,a,h,p,d,o){return e(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="客户端、服务器、浏览器与搜索引擎" tabindex="-1">客户端、服务器、浏览器与搜索引擎 <a class="header-anchor" href="#客户端、服务器、浏览器与搜索引擎" aria-label="Permalink to &quot;客户端、服务器、浏览器与搜索引擎&quot;">​</a></h1><h2 id="是什么与为什么需要" tabindex="-1">是什么与为什么需要 <a class="header-anchor" href="#是什么与为什么需要" aria-label="Permalink to &quot;是什么与为什么需要&quot;">​</a></h2><p>客户端发起网络请求；服务器监听请求并返回资源或计算结果。浏览器是 Web 客户端，负责请求、解析、渲染和执行页面。搜索引擎通过爬取、索引、排序提供检索，搜索结果页不是浏览器也不是目标网站。区分角色有助于判断故障发生在页面代码、网络、服务端还是索引系统。</p><h2 id="四个角色的能力边界" tabindex="-1">四个角色的能力边界 <a class="header-anchor" href="#四个角色的能力边界" aria-label="Permalink to &quot;四个角色的能力边界&quot;">​</a></h2><ul><li>同一程序可在一次通信中是客户端、另一次是服务器；角色由交互决定。</li><li>Web 服务器既可指机器，也可指处理 HTTP 的软件。</li><li>浏览器先请求 HTML，再根据文档继续请求 CSS、脚本、图片等资源。</li><li>搜索引擎能否发现页面取决于链接、抓取许可、可访问响应与索引策略；提交 URL 不保证收录。</li></ul><h2 id="一次页面访问中的角色" tabindex="-1">一次页面访问中的角色 <a class="header-anchor" href="#一次页面访问中的角色" aria-label="Permalink to &quot;一次页面访问中的角色&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sequenceDiagram</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant U as 用户</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant B as 浏览器客户端</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant D as DNS</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant S as Web 服务器</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant C as 搜索引擎爬虫</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    participant I as 搜索索引</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U-&gt;&gt;B: 输入 URL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B-&gt;&gt;D: 查询域名</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D--&gt;&gt;B: 返回地址</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B-&gt;&gt;S: HTTP 请求</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S--&gt;&gt;B: HTML 响应</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B-&gt;&gt;S: 请求 CSS、JS、图片</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C-&gt;&gt;S: 独立抓取公开 URL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S--&gt;&gt;C: 页面与抓取指令</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C-&gt;&gt;I: 解析后决定是否索引</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p>浏览器访问页面与搜索引擎建立索引是两条独立链路。浏览器可以访问某 URL，不代表爬虫允许抓取或搜索引擎选择收录；页面已收录也不保证对某关键词排名靠前。</p><table tabindex="0"><thead><tr><th>角色</th><th>输入</th><th>主要输出</th><th>常见故障</th></tr></thead><tbody><tr><td>浏览器</td><td>URL、用户操作</td><td>DOM、渲染结果、网络请求</td><td>缓存、脚本异常、不兼容</td></tr><tr><td>Web 服务器</td><td>HTTP 请求</td><td>状态、响应头、响应体</td><td>路由、权限、依赖、过载</td></tr><tr><td>搜索爬虫</td><td>可发现 URL</td><td>抓取到的文档</td><td>robots 规则、认证、响应错误</td></tr><tr><td>索引系统</td><td>抓取文档和规范化信号</td><td>可检索条目</td><td>重复内容、质量或索引策略</td></tr></tbody></table><h2 id="从主文档开始的故障定位" tabindex="-1">从主文档开始的故障定位 <a class="header-anchor" href="#从主文档开始的故障定位" aria-label="Permalink to &quot;从主文档开始的故障定位&quot;">​</a></h2><p>在 Network 刷新页面：第一行通常是主 HTML 文档，查看其状态；再检查后续资源。直接输入 URL 是导航；在搜索框输入关键词是向搜索服务查询，两者路径不同。</p><p>定位故障时从可观察边界开始：</p><ol><li>浏览器地址栏确认最终 URL 和重定向。</li><li>Network 查看主文档是否获得可用 HTTP 响应。</li><li>查看响应体是否确为预期 HTML，而不是代理错误页。</li><li>检查后续资源和 Console。</li><li>只在页面本身可访问后，再检查抓取、canonical、robots 和搜索平台报告。</li></ol><h2 id="响应、缓存与搜索摘要边界" tabindex="-1">响应、缓存与搜索摘要边界 <a class="header-anchor" href="#响应、缓存与搜索摘要边界" aria-label="Permalink to &quot;响应、缓存与搜索摘要边界&quot;">​</a></h2><p>“服务器正常”不代表应用响应正确；需检查状态、响应体和控制台。浏览器缓存可能隐藏服务端变化。搜索结果摘要可能过时。浏览器也可展示 PDF、图片等非 HTML 资源。</p><h2 id="internet、web-与多层站点架构" tabindex="-1">Internet、Web 与多层站点架构 <a class="header-anchor" href="#internet、web-与多层站点架构" aria-label="Permalink to &quot;Internet、Web 与多层站点架构&quot;">​</a></h2><p>互联网是通信基础设施，Web 是其上的服务；邮件等服务不属于 Web。一个网站可由 CDN、反向代理、应用服务器和数据库共同提供。</p><h2 id="完整案例的观察目标" tabindex="-1">完整案例的观察目标 <a class="header-anchor" href="#完整案例的观察目标" aria-label="Permalink to &quot;完整案例的观察目标&quot;">​</a></h2><p>选择一个公开页面，记录主文档、一个样式表和一张图片的请求链路，并说明浏览器、服务器和搜索引擎各自能看到什么。完成标准：不把搜索结果页当作网站本身；能区分网络失败、HTTP 错误、页面脚本错误和索引问题；不根据单次缓存访问推断服务端始终正常。</p><h2 id="完整案例-公开文章能访问但搜索不到" tabindex="-1">完整案例：公开文章能访问但搜索不到 <a class="header-anchor" href="#完整案例-公开文章能访问但搜索不到" aria-label="Permalink to &quot;完整案例：公开文章能访问但搜索不到&quot;">​</a></h2><p>输入证据是文章 URL <code>https://example.com/guide/http-cache</code> 在浏览器中能打开，但使用站点搜索和公共搜索引擎都找不到。目标是区分浏览器访问、站点后端、爬虫抓取和索引选择四个环节。</p><h3 id="_1-验证浏览器实际拿到什么" tabindex="-1">1. 验证浏览器实际拿到什么 <a class="header-anchor" href="#_1-验证浏览器实际拿到什么" aria-label="Permalink to &quot;1. 验证浏览器实际拿到什么&quot;">​</a></h3><p>在无登录的私密窗口直接输入 URL，打开 Network 并刷新。记录主文档最终 URL、状态、Content-Type、重定向链和响应体。可用命令补充：</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://example.com/guide/http-cache</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --max-redirs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/null</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;%{url_effective} %{http_code}\\n&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  https://example.com/guide/http-cache</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>curl -I</code> 使用 HEAD，服务器实现可能与 GET 不完全一致；最终仍要在浏览器或普通 GET 中验证。若未登录请求被重定向到登录页，该文章对公共爬虫也不是公开正文。</p><h3 id="_2-检查正文是否在响应中" tabindex="-1">2. 检查正文是否在响应中 <a class="header-anchor" href="#_2-检查正文是否在响应中" aria-label="Permalink to &quot;2. 检查正文是否在响应中&quot;">​</a></h3><p>查看 Response 或页面源代码，搜索文章标题和关键段落。若只有空壳与脚本，浏览器可能依赖 JavaScript 请求 API 后渲染。搜索引擎可能执行脚本，但执行资源、权限和索引策略不同；关键公开内容应在可抓取、稳定的响应路径中提供。</p><table tabindex="0"><thead><tr><th>观察</th><th>可能问题</th><th>下一步</th></tr></thead><tbody><tr><td>404/5xx</td><td>服务器或路由失败</td><td>修复状态和内容后再谈索引</td></tr><tr><td>200 但正文是错误页</td><td>错误状态伪装</td><td>返回正确 4xx/5xx</td></tr><tr><td>302 到登录</td><td>页面不公开</td><td>调整权限或接受不可索引</td></tr><tr><td>200 且 HTML 含正文</td><td>访问层基本可用</td><td>检查爬取与索引信号</td></tr></tbody></table><h3 id="_3-检查爬虫可发现性" tabindex="-1">3. 检查爬虫可发现性 <a class="header-anchor" href="#_3-检查爬虫可发现性" aria-label="Permalink to &quot;3. 检查爬虫可发现性&quot;">​</a></h3><p>文章应从站内正常 <code>a[href]</code> 链接可达，不依赖只能点击脚本按钮生成 URL。检查导航、栏目页、sitemap 和内部链接。sitemap 是 URL 发现提示，不替代链接结构，也不保证收录。</p><p>检查 <code>robots.txt</code> 是否禁止路径，并查看页面 robots meta 或响应 <code>X-Robots-Tag</code>。如果 robots.txt 阻止抓取，爬虫可能无法读取页面内的 <code>noindex</code>；若目标是移除索引，通常需要允许抓取后读取 noindex，具体按搜索平台规则处理。</p><h3 id="_4-区分抓取与索引" tabindex="-1">4. 区分抓取与索引 <a class="header-anchor" href="#_4-区分抓取与索引" aria-label="Permalink to &quot;4. 区分抓取与索引&quot;">​</a></h3><p>使用站点所接入搜索平台的 URL 棖查工具查看最近抓取、抓取响应、用户声明 canonical 和平台选择 canonical。抓取成功仍可能因重复内容、质量、规范化或平台策略不索引。</p><p>canonical 是信号：如果文章错误地指向栏目首页，平台可能把文章视为重复页。修正为真实首选 URL，同时保持内部链接、sitemap、重定向和页面内容信号一致。</p><h3 id="_5-验证站内搜索是另一系统" tabindex="-1">5. 验证站内搜索是另一系统 <a class="header-anchor" href="#_5-验证站内搜索是另一系统" aria-label="Permalink to &quot;5. 验证站内搜索是另一系统&quot;">​</a></h3><p>站内搜索可能查询自有数据库或索引服务，与公共搜索引擎无关。检查文章是否进入发布状态、索引任务是否成功、语言/权限过滤是否把它排除。不能因为公共 URL 可访问就断言站内索引同步成功。</p><h3 id="_6-输出与失败分支" tabindex="-1">6. 输出与失败分支 <a class="header-anchor" href="#_6-输出与失败分支" aria-label="Permalink to &quot;6. 输出与失败分支&quot;">​</a></h3><p>案例输出是一条证据链：公开 GET 返回 200 HTML；正文可见；robots 允许抓取；没有 noindex；canonical 自指；站内链接和 sitemap 可发现；搜索平台报告已抓取。之后仍不能承诺排名或收录，只能等待和持续观察平台状态。</p><p>失败分支：浏览器缓存让已删除页面看似可用，应禁用缓存复测；CDN 与源站响应不一致，应记录实际边缘响应；搜索摘要仍旧是索引刷新延迟，不应通过关键词堆砌强制更新；敏感页面不应靠 robots 隐藏，必须用认证授权。</p><h2 id="客户端与服务器角色的变化" tabindex="-1">客户端与服务器角色的变化 <a class="header-anchor" href="#客户端与服务器角色的变化" aria-label="Permalink to &quot;客户端与服务器角色的变化&quot;">​</a></h2><p>服务端应用调用支付 API 时，它对支付服务是客户端；支付服务回调应用 Webhook 时，应用又是服务器。角色按一次交互的请求发起者和响应者定义，不按机器永久分类。故障定位要标明具体连接、请求方向和责任边界。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://developer.mozilla.org/en-US/docs/Learn_web_development/Getting_started/Web_standards/How_the_web_works" target="_blank" rel="noreferrer">MDN：How the web works</a> — 访问日期：2026-07-17</li><li><a href="https://developer.mozilla.org/en-US/docs/Learn_web_development/Howto/Web_mechanics/What_is_a_web_server" target="_blank" rel="noreferrer">MDN：What is a web server</a> — 访问日期：2026-07-17</li><li><a href="https://developers.google.com/search/docs/fundamentals/how-search-works" target="_blank" rel="noreferrer">Google Search Central：How Search works</a> — 访问日期：2026-07-17</li><li><a href="https://developers.google.com/search/docs/crawling-indexing/robots/intro" target="_blank" rel="noreferrer">Google Search Central：robots.txt introduction</a> — 访问日期：2026-07-17</li></ul>`,43)])])}const k=s(i,[["render",r]]);export{b as __pageData,k as default};
